Email Drafter and Sender Workflow	t	[{"parameters":{"public":true,"initialMessages":"Hi there! 👋\\nMy name is Fernan. How can I assist you today?","options":{"title":"Email Marketer 👋"}},"type":"@n8n/n8n-nodes-langchain.chatTrigger","typeVersion":1.4,"position":[0,0],"id":"6e504c32-13c4-48dc-a7cc-12ee35d0a95a","name":"When chat message received","webhookId":"8bfd79c6-75dc-4a4d-b96b-84c2a293d033"},{"parameters":{"promptType":"define","text":"={{ $json.chatInput }}","options":{"systemMessage":"You are an AI Email Assistant. Your role is to help users draft, improve, and send clear, professional emails based on their instructions.\\n\\nGuidelines:\\n\\nMaintain a polite and professional tone unless the user requests otherwise.\\n\\nAsk for missing details such as recipient, subject, or purpose if unclear.\\n\\nImprove grammar and clarity while keeping the user’s intent.\\n\\nKeep emails concise and well-structured.\\n\\nTool Usage:\\n\\nOnly send emails when the user explicitly asks to send.\\n\\nEnsure recipient, subject, and body are complete before using the email tool.\\n\\nSafety:\\n\\nDo not create spam, scams, impersonation, or harmful content.\\n\\nRespect privacy and refuse illegal or unethical requests."}},"type":"@n8n/n8n-nodes-langchain.agent","typeVersion":3,"position":[208,0],"id":"31045a21-da17-4263-a354-a068ecf5fc67","name":"AI Agent"},{"parameters":{},"type":"@n8n/n8n-nodes-langchain.memoryBufferWindow","typeVersion":1.3,"position":[224,208],"id":"2892c909-4d8b-4c9f-9bc8-45d32c09ccf3","name":"Simple Memory"},{"parameters":{"sendTo":"={{ /*n8n-auto-generated-fromAI-override*/ $fromAI('To', ``, 'string') }}","subject":"={{ /*n8n-auto-generated-fromAI-override*/ $fromAI('Subject', ``, 'string') }}","emailType":"text","message":"={{ /*n8n-auto-generated-fromAI-override*/ $fromAI('Message', ``, 'string') }}","options":{"appendAttribution":false}},"type":"n8n-nodes-base.gmailTool","typeVersion":2.1,"position":[448,208],"id":"0e30cf42-8215-4517-9671-309b074f8