Structured","position":[1640,320],"parameters":{"schemaType":"manual","inputSchema":"{\\n\\t\\"type\\": \\"object\\",\\n\\t\\"properties\\": {\\n\\t\\t\\"start\\": {\\n\\t\\t\\t\\"type\\": \\"string\\"\\n\\t\\t},\\n\\t\\t\\"end\\": {\\n\\t\\t\\t\\"type\\": \\"string\\"\\n\\t\\t}\\n\\t}\\n}"},"typeVersion":1.2},{"id":"f3c416a2-6b42-43cc-aa66-e7d146c1b325","name":"n8n_call","type":"n8n-nodes-base.webhook","position":[-340,120],"webhookId":"b352dd49-d3b3-4e0a-a781-17137f7199c8","parameters":{"path":"b352dd49-d3b3-4e0a-a781-17137f7199c8","options":{},"httpMethod":"POST"},"typeVersion":2},{"id":"2862b10c-77d7-4555-b9ec-86c9c4b9fe7b","name":"Sticky Note","type":"n8n-nodes-base.stickyNote","position":[1080,-1140],"parameters":{"width":1140,"height":920,"content":"# STEP 3 - RETELL AI\\n\\n- Register on [Retell AI](https://retellai.com) (10$ FREE credits)\\n- Create an Agent an set \\"Voice & Language\\" and add your system prompt\\n- In Webhook settings add the \\"Agent Level Webhook URL\\" with the n8n webhook node url called \\"n8n_call\\"\\n- Buy a new phone number with your FREE credits by Twilio Provider and connect it to the created agent\\n- Enter the previously created agency and create the flow as shown in the following image\\n![image](https://i.postimg.cc/brtBkgfH/Retellai-flow.png)\\n- Aggiungere 2 funzioni (una per RAG e una per il Booking) e inserire l'url apposito ricavato dai webhook di n8n \\"n8n_rag_function\\" e \\"n8n_check_available\\"\\n\\n"},"typeVersion":1},{"id":"98de797e-56d8-42b4-85a5-245ae7d086db","name":"Sticky Note1","type":"n8n-nodes-base.stickyNote","position":[-340,-100],"parameters":{"color":5,"width":1220,"content":"# STEP 4\\nIntercept the \\"end call\\" event and get the full call transcript\\n- Add your CHAT_ID in Telegram node"},"typeVersion":1},{"id":"ccf11ce4-3bc4-46bd-a71e-12e59d7a2504","name":"n8n_check_available","type":"n8n-nodes-base.webhook","position":[1120,100],"webhookId":"4dcd68b1-91d3-40bc-8aa6-c681126752b2","parameters":