ase.wait","position":[704,528],"webhookId":"344c2d5d-5629-4466-866b-ac6359b3b042","typeVersion":1.1},{"parameters":{"method":"POST","url":"https://api.retellai.com/v2/create-phone-call","sendHeaders":true,"headerParameters":{"parameters":[{"name":"Authorization","value":"Bearer key_XXXXXXXXX"},{"name":"Content-Type","value":"application/json"}]},"sendBody":true,"specifyBody":"json","jsonBody":"={\\n  \\"from_number\\": \\"+33600000000\\",\\n  \\"to_number\\": \\"{{ $json['Phone Number'] }}\\",\\n  \\"retell_llm_dynamic_variables\\": {\\n    \\"uuid\\": \\"{{ $('Detect new lead in Google Sheets').item.json.UUID }}\\"\\n  }\\n}","options":{}},"id":"c8fa63ce-39f1-4523-afb5-aed14aa6b55c","name":"Call new lead using RetellAI","type":"n8n-nodes-base.httpRequest","position":[1008,528],"typeVersion":4.2},{"parameters":{"httpMethod":"POST","path":"ebd11c9b-129c-4b59-8c27-9a4b567305f7","responseMode":"responseNode","options":{}},"id":"0ad9ca98-1978-4c8f-8482-5ee0911ab610","name":"Receive inbound call from RetellAI (webhook)","type":"n8n-nodes-base.webhook","position":[80,880],"webhookId":"ebd11c9b-129c-4b59-8c27-9a4b567305f7","typeVersion":2},{"parameters":{"documentId":{"__rl":true,"mode":"id","value":"="},"sheetName":{"__rl":true,"mode":"id","value":"="},"filtersUI":{"values":[{"lookupColumn":"Phone Number","lookupValue":"={{ $json.body.call_inbound.from_number }}"}]},"options":{}},"id":"f9fd1607-c2bd-4a32-bf30-35defa256d92","name":"Check if phone number exists in Google Sheets","type":"n8n-nodes-base.googleSheets","position":[544,880],"typeVersion":4.5},{"parameters":{"respondWith":"json","responseBody":"={\\n  \\"call_inbound\\": {\\n    \\"dynamic_variables\\": {\\n        \\"name\\": \\"{{ $json.Name }}\\"\\n    }\\n  }\\n}","options":{}},"id":"718f0a54-593d-4ccd-84c6-b24d940fb1a8","name":"Send response to inbound webhook call","type":"n8n-nodes-base.respondToWebhook","position":[1008,880],"typeVersion":1.1},{"parameters":{"httpMethod":"POST","path":"f8878b78-43ea-4caa-